args.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?religionLabel
WHERE {
  ?province rdfs:label 'British Columbia'@en ;
             wdt:P17 wd:Q16 .
  ?province wdt:P2548 ?religion .
  ?religion rdfs:label ?religionLabel .
  FILTER (LANG(?religionLabel) = 'en')
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?province
WHERE {
  ?province rdfs:label 'British Columbia'@en
}
